select count(*) from postgres.comments as c, postgres.posts as p, postgres.posthistory as ph, postgres.votes as v, postgres.users as u where v.userid = u.id and c.userid = u.id and p.owneruserid = u.id and ph.userid = u.id and p.viewcount>=0 and p.answercount>=0 and p.answercount<=5 and ph.posthistorytypeid=2 and ph.creationdate>=timestamp '2010-11-05 01:25:39' and ph.creationdate<=timestamp '2014-09-09 07:14:12' and v.bountyamount>=0 and v.bountyamount<=100 and v.creationdate>=timestamp '2010-07-26 00:00:00' and u.views>=0 and u.views<=13;
